(()=>{document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("contact-form");t&&t.addEventListener("submit",async a=>{a.preventDefault();const s=document.getElementById("contact-name").value,c=document.getElementById("contact-email").value,r=document.getElementById("contact-subject").value,d=document.getElementById("contact-message").value,e=t.querySelector('button[type="submit"]'),l=e.textContent;e.textContent="Odes\xEDl\xE1m...",e.disabled=!0;try{const n=window.getCSRFToken?await window.getCSRFToken():null,o=await(await fetch("/api/contact",{method:"POST",headers:{"Content-Type":"application/json",...n&&{"X-CSRF-Token":n}},body:JSON.stringify({name:s,email:c,subject:r,message:d})})).json();o.success?(alert(o.message||"Zpr\xE1va byla odesl\xE1na!"),t.reset()):alert(o.error||"Chyba p\u0159i odes\xEDl\xE1n\xED zpr\xE1vy.")}catch(n){console.error("Contact Form Error:",n),alert("Chyba p\u0159i odes\xEDl\xE1n\xED zpr\xE1vy. Zkuste to pros\xEDm pozd\u011Bji.")}finally{e.textContent=l,e.disabled=!1}})});})();
